import { ExternalTokenizer, type Stack } from '@lezer/lr';

import { RESERVED_CHARACTERS } from '../../utils/escape-suggestion.js';
import { characterCodes } from '../character-codes.js';
import { filterFieldKeywords } from '../keywords.js';
import {
  FreeText,
  InvalidIdentifier,
  String as StringToken,
} from '../parser.terms.js';
import { tokenizeString } from './string-tokenizer.js';
import { advanceAndAcceptFreeText } from '../utils/accept-free-text.js';
import { getTextFromStream } from '../utils/get-text-from-stream.js';
import { matchCharacterSequence } from '../utils/match-character-sequence.js';

const {
  BACKSLASH,
  CLOSING_BRACKET,
  DOLLAR,
  DOUBLEQUOTE,
  EOF,
  OPENING_BRACKET,
  SPACE,
} = characterCodes;

const matchDefaultCharacter = new RegExp(
  `(?:[^${RESERVED_CHARACTERS}aoin]|\\s)+`,
  'i',
);

const lastTokenizationEndIndexCache = new WeakMap<Stack, number>();
const endFreeText = [OPENING_BRACKET, CLOSING_BRACKET];

/** @internal */
export const textTokenizer = new ExternalTokenizer((inputStream, stack) => {
  const lastTokenizationEndIndex =
    lastTokenizationEndIndexCache.get(stack) ?? 0;

  // Reset the last tokenized index when reaching the end of the input stream and return;
  if (inputStream.next === -1) {
    lastTokenizationEndIndexCache.set(stack, 0);
    return;
  }

  // We already checked all characters until the last end index and can return if the stream is not there yet.
  if (stack.pos < lastTokenizationEndIndex) {
    return;
  }

  if (
    stack.context.lastToken === 'ComparisonOperator' &&
    inputStream.next === DOLLAR
  ) {
    let nextChar = inputStream.peek(1);

    if (
      nextChar === EOF ||
      nextChar === SPACE ||
      nextChar === OPENING_BRACKET
    ) {
      if (nextChar === SPACE) {
        let nextOffset = 2;
        nextChar = inputStream.peek(nextOffset);
        while (nextChar !== EOF && nextChar === SPACE) {
          nextOffset += 1;
          nextChar = inputStream.peek(nextOffset);
        }

        if (nextChar === EOF) {
          inputStream.acceptToken(FreeText, nextOffset);
          return;
        }
      }

      inputStream.acceptToken(InvalidIdentifier, 1);
      return;
    }
  }

  // A free text token may overlap with a string token. In order to accept the correct token,
  // we need to store whether we started tokenizing a string already.
  let startedStringTokenization = false;
  // Variable for tracking how far we looked ahead already.
  let offset = 0;

  // Token starts with doublequotes, may be a string.
  if (inputStream.next === DOUBLEQUOTE) {
    const { token, offset: stringOffset } = tokenizeString(
      inputStream,
      stack,
      lastTokenizationEndIndexCache,
    );
    offset = stringOffset;

    if (token === 'string') {
      return;
    } else if (token === 'indeterminate') {
      startedStringTokenization = true;
    }
  }

  // If we already started detecting a JSONPath, a free text can't be valid at this point.
  if (stack.context.lastToken === 'JsonPathBase') {
    return;
  }

  // If we already started detecting a string, but the next character is a doublequote again, we
  // can accept everything until this point as free text. Tokenization will continue at the next character
  // again (the currently evaluated doublequote).
  // E.g.:
  // """a" = b
  // --> ›""‹›"a" = b‹
  if (
    startedStringTokenization &&
    (inputStream.peek(offset) === DOUBLEQUOTE ||
      inputStream.peek(offset) === -1)
  ) {
    inputStream.acceptToken(FreeText, offset);
    return;
  }

  // Free text is only valid if there is no token yet or the previous
  // expression is complete and we're starting a new expression.
  // Else, we can hand back over to the parser.
  if (
    !(
      stack.context.lastToken === null ||
      stack.context.lastToken === 'expression' ||
      stack.context.validExpression === true
    )
  ) {
    return;
  }

  // Current numeric representation of the code unit we are checking.
  let currentCharCode = inputStream.peek(offset);
  // String representation of the code unit we are checking.
  let currentCharacter = String.fromCharCode(currentCharCode);

  let excludePreviousToken = false;

  // A leading space should only be inlcuded in the free text if there is no token yet to avoid
  // highlighting the automatically added edit-mode space as an incomplete statement.
  if (
    currentCharCode === SPACE &&
    stack.context.lastToken !== null &&
    !startedStringTokenization
  ) {
    return;
  }

  // Whether a keyword has been matched. If so, we can advance the stream until after the keyword
  // so we don't start with matching the keyword when the tokenizer is invoked the next time.
  let matchedKeyword = false;

  // Increase the offset as long as a free text may still be valid.
  while (currentCharCode > -1) {
    // Include escaped character.
    if (currentCharCode === BACKSLASH) {
      // The offset can be increased an additional time to include both the escape character
      // and the escaped character.
      offset += 1;
      peekNext();
      continue;
    }

    // End free text tokenization if the current character is included in the
    // list of characters terminating a free text.
    if (endFreeText.includes(currentCharCode)) {
      break;
    }

    // If the current code unit matches a doublequote, we can abort the free text tokenization since it
    // should be handled in a subsequent tokenization as a potential string token.
    if (currentCharCode === DOUBLEQUOTE) {
      const { token, offset: stringOffset } = tokenizeString(
        inputStream,
        stack,
        lastTokenizationEndIndexCache,
        offset,
      );

      if (token === 'json') {
        inputStream.acceptTokenTo(FreeText, offset);
        break;
      } else if (token === 'string') {
        const textBeforeString = getTextFromStream(inputStream, offset);

        // Ignore preceding spaces to avoid splitting up a filter starting with a space
        // into multiple statements.
        // E.g. › "foo" = bar‹ the leading space should be ignored.
        if (textBeforeString.length > 0 && textBeforeString.trim() === '') {
          // If there's only spaces before, advance the stream to start the next
          // tokenization only after the spaces.
          inputStream.advance(offset);
          return;
        }

        lastTokenizationEndIndexCache.set(stack, stringOffset);
        inputStream.acceptTokenTo(StringToken, stringOffset);
        break;
      } else {
        offset = stringOffset;
        peekNext();
      }
    }

    // If the current character matches any normal character, include it in the free text token and move on.
    if (matchDefaultCharacter.test(currentCharacter)) {
      peekNext();
      continue;
    }

    // If any other character is encountered (special character, starting character of keywords), we only
    // continue a free text token under certain conditions...
    const {
      keyword: matchString,
      needsFilterKey,
      leading,
      trailing,
    } = filterFieldKeywords[currentCharacter.toLowerCase()] ?? {};

    // If the current character starts a keyword, check if a keyword actually matches.
    // If yes, stop matching free text.
    if (
      matchString !== undefined &&
      matchCharacterSequence({
        inputStream,
        offset,
        characterSequence: matchString,
        leading,
        trailing,
      })
    ) {
      matchedKeyword = true;
      excludePreviousToken = !!needsFilterKey;

      // If there are no characters prior to the matched keyword, we include the character in the free text
      // even though a filter key is not present.
      // E.g.:
      // =a --> = would need a key. We are still at 0 offset. So we include it in the free text after all.
      if (needsFilterKey && offset === 0) {
        excludePreviousToken = false;
        peekNext();
        continue;
      }

      // If a keyword matched, abort matching free text.
      break;
    }

    // We did check for a keyword and special characters, but no matches were found -> we can include
    // the current character in the free text and continue to the next.
    peekNext();
  }

  if (offset > 0 || startedStringTokenization) {
    lastTokenizationEndIndexCache.set(
      stack,
      lastTokenizationEndIndex + offset + (matchedKeyword ? 1 : 0),
    );
    advanceAndAcceptFreeText(
      inputStream,
      stack,
      offset,
      startedStringTokenization,
      lastTokenizationEndIndexCache,
      excludePreviousToken,
    );
  }

  /** Set all variables needed to determine whether we should continue checking for a FreeText node. */
  function peekNext() {
    offset += 1;
    currentCharCode = inputStream.peek(offset);
    currentCharacter = String.fromCharCode(currentCharCode);
  }
});
